import torch
import torch.nn as nn
import torch.nn.functional as F
import torch.distributed as dist


def _world_size():
    if dist.is_available() and dist.is_initialized():
        return dist.get_world_size()
    return 1


def _rank():
    if dist.is_available() and dist.is_initialized():
        return dist.get_rank()
    return 0


class _GatherFromLastDim(torch.autograd.Function):
    """Differentiable all_gather that concatenates along the last dimension."""

    @staticmethod
    def forward(ctx, input_):
        world_size = _world_size()
        if world_size == 1:
            return input_
        input_ = input_.contiguous()
        tensor_list = [torch.empty_like(input_) for _ in range(world_size)]
        dist.all_gather(tensor_list, input_)
        # keep the local shard connected to the autograd graph
        tensor_list[_rank()] = input_
        return torch.cat(tensor_list, dim=-1)

    @staticmethod
    def backward(ctx, grad_output):
        world_size = _world_size()
        if world_size == 1:
            return grad_output
        dim_size = grad_output.size(-1) // world_size
        grads = torch.split(grad_output, dim_size, dim=-1)
        return grads[_rank()].contiguous()


class _AllReduceSum(torch.autograd.Function):
    """Differentiable all_reduce (sum) across ranks."""

    @staticmethod
    def forward(ctx, input_):
        if _world_size() == 1:
            return input_
        input_ = input_.contiguous()
        dist.all_reduce(input_)
        return input_

    @staticmethod
    def backward(ctx, grad_output):
        return grad_output


class ColumnParallelLinear(nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        self.in_features = in_features
        self.out_features = out_features

        world_size = _world_size()
        rank = _rank()
        assert out_features % world_size == 0, \
            "out_features must be divisible by world_size"
        self.out_features_per_partition = out_features // world_size

        start = rank * self.out_features_per_partition
        end = start + self.out_features_per_partition
        # weight: [out_features, in_features], split along dim 0 (output dim)
        weight_shard = master_weight[start:end, :].clone().detach().contiguous()
        self.weight = nn.Parameter(weight_shard)

        if bias:
            self.bias = nn.Parameter(
                torch.zeros(self.out_features_per_partition,
                            dtype=self.weight.dtype,
                            device=self.weight.device))
        else:
            self.register_parameter("bias", None)

    def forward(self, input_):
        local_output = F.linear(input_, self.weight, self.bias)
        return _GatherFromLastDim.apply(local_output)


class RowParallelLinear(nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        self.in_features = in_features
        self.out_features = out_features

        world_size = _world_size()
        rank = _rank()
        assert in_features % world_size == 0, \
            "in_features must be divisible by world_size"
        self.in_features_per_partition = in_features // world_size

        start = rank * self.in_features_per_partition
        end = start + self.in_features_per_partition
        # weight: [out_features, in_features], split along dim 1 (input dim)
        weight_shard = master_weight[:, start:end].clone().detach().contiguous()
        self.weight = nn.Parameter(weight_shard)

        if bias:
            # bias stays full on every rank
            self.bias = nn.Parameter(
                torch.zeros(out_features,
                            dtype=self.weight.dtype,
                            device=self.weight.device))
        else:
            self.register_parameter("bias", None)

    def forward(self, input_):
        # input_ is already the local shard along the last (input) dimension
        local_output = F.linear(input_, self.weight)
        output = _AllReduceSum.apply(local_output)
        if self.bias is not None:
            output = output + self.bias
        return output

